(function(){function showState(state,loading,success,processing){if(loading)loading.style.display='none';if(success)success.style.display='none';if(processing)processing.style.display='none';if(state)state.style.display='';}
async function initCheckoutReturn(){var params=new URLSearchParams(window.location.search);var sessionId=params.get('session_id');var loading=document.getElementById('return-loading');var success=document.getElementById('return-success');var processing=document.getElementById('return-processing');var syncMessage=document.getElementById('return-sync-message');if(!sessionId){showState(processing,loading,success,processing);return;}
try{var response=await fetch('/api/get-checkout-session?session_id='+encodeURIComponent(sessionId));var data=await response.json().catch(function(){return{};});if(data.ok&&data.status==='complete'){var label=document.getElementById('return-offer-label');if(label&&data.offer_label)label.textContent=data.offer_label;var dashLink=document.getElementById('return-dashboard-link');if(dashLink&&data.dashboard_url)dashLink.href=data.dashboard_url;if(syncMessage){syncMessage.textContent='Syncing your purchase to your ExEF account...';}
if(window.EFI&&EFI.Auth&&typeof EFI.Auth.addOfferPurchase==='function'&&data.offer&&data.payment_intent_id){try{await EFI.Auth.addOfferPurchase(data.offer,data.payment_intent_id,data.customer_email||'');if(typeof EFI.Auth.refreshManagedSession==='function'){await EFI.Auth.refreshManagedSession();}
if(syncMessage){syncMessage.textContent='Purchase synced to your dashboard and verification record.';}}catch(err){if(syncMessage){syncMessage.textContent=err&&err.message?err.message:'Payment confirmed. Sign in with the purchasing email to sync access.';}}}else if(syncMessage){syncMessage.textContent='Payment confirmed. Sign in with the purchasing email to sync access.';}
showState(success,loading,success,processing);return;}}catch(err){}
showState(processing,loading,success,processing);}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initCheckoutReturn);}else{initCheckoutReturn();}})();